package org.jsoup.parser.steps;

import io.cucumber.java8.En;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import static org.junit.Assert.*;

public class StepDefs implements En {

    private String inputHtml;
    private Document resultDocument;

    public StepDefs() {
        Given("the input HTML is {string}", (String html) -> {
            inputHtml = html;
        });

        When("the input is parsed", () -> {
            try {
                resultDocument = Jsoup.parse(inputHtml);
            } catch (Exception e) {
                // Capture the exception if needed for error testing
                resultDocument = null;
            }
        });

        Then("the result body HTML should be {string}", (String expectedBodyHtml) -> {
            assertNotNull("Document should not be null", resultDocument);
            String actualBodyHtml = resultDocument.body().html();
            // Normalize whitespace for comparison
            String normalizedActual = actualBodyHtml.replaceAll("\\s+", " ").trim();
            String normalizedExpected = expectedBodyHtml.replaceAll("\\s+", " ").trim();
            assertEquals("Body HTML should match expected", normalizedExpected, normalizedActual);
        });

        Then("the text {string} should be present in the body", (String expectedText) -> {
            assertNotNull("Document should not be null", resultDocument);
            String bodyText = resultDocument.body().text();
            assertTrue("Body should contain text: " + expectedText, bodyText.contains(expectedText));
        });

        Then("the text {string} should be present in the paragraph element", (String expectedText) -> {
            assertNotNull("Document should not be null", resultDocument);
            Element paragraph = resultDocument.selectFirst("p");
            assertNotNull("Paragraph element should exist", paragraph);
            String paragraphText = paragraph.text();
            assertTrue("Paragraph should contain text: " + expectedText, paragraphText.contains(expectedText));
        });
    }
}

